import{_ as a,o as r,c as e,a2 as d}from"./chunks/framework.DIMps2S2.js";const b=JSON.parse('{"title":"结构化产品","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"funds-and-wealth/structured-products.md","filePath":"zh-CN/funds-and-wealth/structured-products.md"}'),o={name:"funds-and-wealth/structured-products.md"};function l(n,t,i,h,s,u){return r(),e("div",null,[...t[0]||(t[0]=[d('<h1 id="结构化产品" tabindex="-1">结构化产品 <a class="header-anchor" href="#结构化产品" aria-label="Permalink to &quot;结构化产品&quot;">​</a></h1><p>结构化产品是将固定收益工具与衍生品结合设计的投资产品，适合对特定市场走势有判断、追求条件性增强收益的投资者。入口在「市场」→「财富」→「结构化产品」。</p><blockquote><p>结构化产品具有较高复杂性，购买前系统会进行风险评估，请确认自己理解产品结构后再投资。</p></blockquote><h2 id="主要产品类型" tabindex="-1">主要产品类型 <a class="header-anchor" href="#主要产品类型" aria-label="Permalink to &quot;主要产品类型&quot;">​</a></h2><h3 id="雪球产品-snowball" tabindex="-1">雪球产品（Snowball） <a class="header-anchor" href="#雪球产品-snowball" aria-label="Permalink to &quot;雪球产品（Snowball）&quot;">​</a></h3><p>雪球是一种与标的资产挂钩的结构性票据，核心机制为「敲出」与「敲入」：</p><table tabindex="0"><thead><tr><th>机制</th><th>触发条件</th><th>结果</th></tr></thead><tbody><tr><td>敲出（Knock-out）</td><td>标的价格上涨至敲出界限</td><td>产品提前终止，投资者获得约定票息收益</td></tr><tr><td>敲入（Knock-in）</td><td>标的价格下跌至敲入界限</td><td>产品继续运行，到期时可能承担下行损失</td></tr><tr><td>到期未敲入未敲出</td><td>价格在区间内运行至到期</td><td>获得约定票息</td></tr></tbody></table><p><strong>标的类型</strong>：</p><ul><li>指数雪球：挂钩恒生指数（HSI）、恒生科技指数（HSTECH）等</li><li>个股雪球：挂钩 META、台积电（TSM）、阿里巴巴（BABA）等个股</li></ul><p><strong>展示信息</strong>：敲出界限、行权水平（敲入界限）、期限、年化票息率。</p><p>雪球适合判断标的「震荡偏上行、不大涨也不大跌」的市场环境：大涨则被敲出提前结束；大跌触发敲入后持有到期可能亏损本金。触发敲入后，若到期时标的价格仍低于行权水平，票息可能无法弥补本金损失；仅在未触发敲入（或敲入后标的价格回升至行权水平以上）时，才能获得完整票息。</p><h3 id="固定票息票据-fixed-coupon-note" tabindex="-1">固定票息票据（Fixed Coupon Note） <a class="header-anchor" href="#固定票息票据-fixed-coupon-note" aria-label="Permalink to &quot;固定票息票据（Fixed Coupon Note）&quot;">​</a></h3><p>在持有期内定期支付固定票息，到期返还本金（通常有本金保障条款）。适合追求稳定现金流的投资者。</p><h3 id="逐步递减自动敲出票据" tabindex="-1">逐步递减自动敲出票据 <a class="header-anchor" href="#逐步递减自动敲出票据" aria-label="Permalink to &quot;逐步递减自动敲出票据&quot;">​</a></h3><p>敲出价格随时间逐步降低的雪球变体，越临近到期越容易触发敲出，增加提前结束概率。</p><h2 id="产品信息字段" tabindex="-1">产品信息字段 <a class="header-anchor" href="#产品信息字段" aria-label="Permalink to &quot;产品信息字段&quot;">​</a></h2><table tabindex="0"><thead><tr><th>字段</th><th>说明</th></tr></thead><tbody><tr><td>期限</td><td>产品存续时间（如 12 个月、24 个月）</td></tr><tr><td>票息</td><td>年化收益率（如 12.13%）</td></tr><tr><td>敲出界限</td><td>触发提前终止的价格水平（通常为初始价格的 100%~103%）</td></tr><tr><td>行权水平</td><td>敲入价格（通常为初始价格的 70%~80%）</td></tr><tr><td>标的</td><td>挂钩的股票或指数</td></tr></tbody></table><h2 id="投资门槛与购买条件" tabindex="-1">投资门槛与购买条件 <a class="header-anchor" href="#投资门槛与购买条件" aria-label="Permalink to &quot;投资门槛与购买条件&quot;">​</a></h2><ul><li><strong>投资门槛</strong>：不同产品起点不同，通常从 1 万港元/美元起，部分产品要求更高，以产品详情页说明为准</li><li><strong>购买资格</strong>：需完成风险评估问卷，达到平台要求的风险承受等级（通常为中高或以上风险）。部分产品仅对专业投资者开放</li></ul><h2 id="风险提示" tabindex="-1">风险提示 <a class="header-anchor" href="#风险提示" aria-label="Permalink to &quot;风险提示&quot;">​</a></h2><ul><li><strong>本金风险</strong>：触发敲入且到期时标的价格低于敲入价，投资者可能损失本金</li><li><strong>流动性风险</strong>：结构化产品通常不可提前赎回，存续期间资金被锁定</li><li><strong>发行方风险</strong>：产品收益与发行机构信用挂钩，需关注发行方资质</li></ul><h2 id="引用此页面的文档" tabindex="-1">引用此页面的文档 <a class="header-anchor" href="#引用此页面的文档" aria-label="Permalink to &quot;引用此页面的文档&quot;">​</a></h2><ul><li><a href="/wiki/funds-and-wealth">基金与理财</a></li></ul>',23)])])}const p=a(o,[["render",l]]);export{b as __pageData,p as default};
